import React, { useState, useEffect } from "react";
import axios from "axios";

const Dashboard = () => {
  const [lots, setLots] = useState([]);
  const [error, setError] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [statusSearchTerm, setStatusSearchTerm] = useState("");
  const [inspectionTypeSearchTerm, setInspectionTypeSearchTerm] = useState("");
  const [inspectorSearchTerm, setInspectorSearchTerm] = useState("");

  useEffect(() => {
    fetchLots();
  }, []);

  const fetchLots = async () => {
    try {
      const response = await axios.get("http://localhost:5001/api/lots");
      setLots(response.data);
    } catch (error) {
      console.error("Error fetching lots:", error);
      setError("Failed to load lots");
    }
  };

  return (
    <div>
      <h1>Dashboard</h1>

      {/* KPIs */}
      <div className="kpis">
        <div className="kpi">
          <h1>2,000</h1>
          <p>Lots Inspected</p>
        </div>
        <div className="kpi">
          <h1>3,500</h1>
          <p>Samples</p>
        </div>
        <div className="kpi">
          <h1>2.50</h1>
          <p>Avg. Condition Score</p>
        </div>
        <div className="kpi">
          <h1>2.20</h1>
          <p>Avg Quality Score</p>
        </div>
      </div>

      {/* Summary table */}
      <div className="inspectors-list">
        <h3>Current Lots</h3>

        {error && <div className="error-message">{error}</div>}
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>
                  <div className="table-header">
                    Lot Number
                    <input
                      type="text"
                      placeholder="Search by Lot Number"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                      className="search-input"
                    />
                  </div>
                </th>
                <th>
                  <div className="table-header">
                    Inspection Type
                    <input
                      type="text"
                      placeholder="Search by Inspection Type"
                      value={inspectionTypeSearchTerm}
                      onChange={(e) => setInspectionTypeSearchTerm(e.target.value)}
                      className="search-input"
                    />
                  </div>
                </th>
                <th>
                  <div className="table-header">
                    Status
                    <input
                      type="text"
                      placeholder="Search by Status"
                      value={statusSearchTerm}
                      onChange={(e) => setStatusSearchTerm(e.target.value)}
                      className="search-input"
                    />
                  </div>
                </th>
                <th>
                  <div className="table-header">
                    Inspector
                    <input
                      type="text"
                      placeholder="Search by Inspector"
                      value={inspectorSearchTerm}
                      onChange={(e) => setInspectorSearchTerm(e.target.value)}
                      className="search-input"
                    />
                  </div>
                </th>
              </tr>
            </thead>
            <tbody>
              {lots
                .filter(lot =>
                  lot.lotNumber.toLowerCase().includes(searchTerm.toLowerCase()) &&
                  lot.status.toLowerCase().includes(statusSearchTerm.toLowerCase()) &&
                  lot.inspectionType.toLowerCase().includes(inspectionTypeSearchTerm.toLowerCase()) &&
                  lot.inspectorName.toLowerCase().includes(inspectorSearchTerm.toLowerCase())
                )
                .map(lot => (
                  <tr key={lot._id}>
                    <td>{lot.lotNumber}</td>
                    <td>{lot.inspectionType}</td>
                    <td>{lot.status}</td>
                    <td>{lot.inspectorName}</td>
                  </tr>
                ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
